    #[test]
    fn waiting_list_append_hold_snapshot_actor_uses_runtime_subscribers_for_pending_nested_list_snapshot()
     {
        let scope_id = crate::engine::create_registry_scope(None);
        let _scope_guard = ScopeDestroyGuard::new(scope_id);
        let actor_context = ActorContext {
            registry_scope_id: Some(scope_id),
            ..ActorContext::default()
        };
        let construct_context = ConstructContext {
            construct_storage: Arc::new(crate::engine::ConstructStorage::in_memory_for_tests(
                std::collections::BTreeMap::new(),
            )),
            virtual_fs: VirtualFilesystem::new(),
            bridge_scope_id: None,
            scene_ctx: None,
        };

        let existing_item = crate::engine::Text::new_arc_value_actor(
            crate::engine::ConstructInfo::new(
                "test.list_append.waiting_snapshot.existing_item",
                None,
                "test list append waiting snapshot existing item",
            ),
            construct_context.clone(),
            crate::engine::ValueIdempotencyKey::new(),
            actor_context.clone(),
            "existing",
        );
        let list_actor = crate::engine::create_constant_actor(
            boon::parser::PersistenceId::new(),
            Value::List(
                Arc::new(crate::engine::List::new(
                    crate::engine::ConstructInfo::new(
                        "test.list_append.waiting_snapshot.source_list",
                        None,
                        "test list append waiting snapshot source list",
                    ),
                    construct_context.clone(),
                    actor_context.clone(),
                    vec![existing_item],
                )),
                crate::engine::ValueMetadata::new(crate::engine::ValueIdempotencyKey::new()),
            ),
            scope_id,
        );

        let (mut nested_list_tx, nested_list_rx) = mpsc::channel::<crate::engine::ListChange>(8);
        let pending_nested_list = Arc::new(crate::engine::List::new_with_change_stream(
            crate::engine::ConstructInfo::new(
                "test.list_append.waiting_snapshot.pending_nested_list",
                None,
                "test list append waiting snapshot pending nested list",
            ),
            actor_context.clone(),
            nested_list_rx,
            (),
        ));
        let item_actor = crate::engine::create_constant_actor(
            boon::parser::PersistenceId::new(),
            Value::List(
                pending_nested_list,
                crate::engine::ValueMetadata::new(crate::engine::ValueIdempotencyKey::new()),
            ),
            scope_id,
        );

        let baseline_async_source_count =
            crate::engine::REGISTRY.with(|reg| reg.borrow().async_source_count_for_scope(scope_id));

        let result_actor = super::create_waiting_list_append_hold_snapshot_actor_with_registry(
            None,
            list_actor,
            item_actor,
            construct_context.clone(),
            actor_context.clone(),
        );

        crate::engine::REGISTRY.with(|reg| {
            let reg = reg.borrow();
            assert_eq!(
                reg.async_source_count_for_scope(scope_id),
                baseline_async_source_count,
                "waiting HOLD snapshot append should reuse runtime/list subscribers without adding another snapshot waiter task"
            );
        });

        assert!(
            result_actor.current_value().is_err(),
            "result should stay pending until the nested list snapshot becomes available"
        );

        let nested_item = crate::engine::Text::new_arc_value_actor(
            crate::engine::ConstructInfo::new(
                "test.list_append.waiting_snapshot.nested_item",
                None,
                "test list append waiting snapshot nested item",
            ),
            construct_context.clone(),
            crate::engine::ValueIdempotencyKey::new(),
            actor_context.clone(),
            "nested",
        );
        nested_list_tx
            .try_send(crate::engine::ListChange::Replace {
                items: Arc::from(vec![nested_item]),
            })
            .expect("pending nested list should accept its first replace");
        for _ in 0..3 {
            crate::engine::poll_test_async_source_tasks();
        }

        let Value::List(result_list, _) = result_actor
            .current_value()
            .expect("result should resolve once the nested list snapshot becomes available")
        else {
            panic!("result should resolve to a list");
        };

        let snapshot = block_on(result_list.snapshot());
        assert_eq!(
            snapshot.len(),
            2,
            "result list should contain existing and appended items"
        );

        let Value::Text(existing, _) = snapshot[0]
            .1
            .current_value()
            .expect("existing item should expose current value")
        else {
            panic!("existing item should stay text");
        };
        assert_eq!(existing.text(), "existing");

        let Value::List(appended_list, _) = snapshot[1]
            .1
            .current_value()
            .expect("appended item should expose the materialized nested list")
        else {
            panic!("appended item should resolve to a list");
        };
        let nested_snapshot = block_on(appended_list.snapshot());
        assert_eq!(
            nested_snapshot.len(),
            1,
            "materialized appended nested list should expose its initialized snapshot"
        );
        let Value::Text(nested_text, _) = nested_snapshot[0]
            .1
            .current_value()
            .expect("nested appended item should expose current value")
        else {
            panic!("nested appended item should stay text");
        };
        assert_eq!(nested_text.text(), "nested");
    }

