    #[test]
    fn piped_user_defined_function_builtin_round_body_with_lazy_input_uses_one_scope_task() {
        let scope_id = crate::engine::create_registry_scope(None);
        let _scope_guard = ScopeDestroyGuard::new(scope_id);
        let actor_context = ActorContext {
            registry_scope_id: Some(scope_id),
            ..ActorContext::default()
        };
        let construct_context = ConstructContext {
            construct_storage: Arc::new(crate::engine::ConstructStorage::in_memory_for_tests(
                std::collections::BTreeMap::new(),
            )),
            virtual_fs: VirtualFilesystem::new(),
            bridge_scope_id: None,
            scene_ctx: None,
        };
        let (source_code, expressions) =
            parse_static_program("FUNCTION rounded(x) { x |> Math/round() }");
        let function_def = expressions
            .into_iter()
            .find_map(|expr| match expr.node {
                static_expression::Expression::Function {
                    name,
                    parameters,
                    body,
                } if name.to_string() == "rounded" => Some(super::StaticFunctionDefinition {
                    parameters: parameters
                        .into_iter()
                        .map(|param| param.node.to_string())
                        .collect(),
                    body: *body,
                    module_name: None,
                }),
                _ => None,
            })
            .expect("rounded function should parse");
        let mut function_registry = FunctionRegistry::new();
        function_registry.insert(String::from("rounded"), function_def);

        let (mut input_tx, input_rx) = mpsc::channel::<Value>(8);
        let input_actor = crate::engine::create_actor_lazy(
            input_rx,
            boon::parser::PersistenceId::new(),
            scope_id,
        );
        let baseline_async_source_count =
            crate::engine::REGISTRY.with(|reg| reg.borrow().async_source_count_for_scope(scope_id));

        let result_actor = super::call_function(
            vec![String::from("rounded")],
            vec![],
            (0..0).into(),
            None,
            boon::parser::PersistenceId::new(),
            super::EvaluationContext {
                construct_context: construct_context.clone(),
                actor_context: ActorContext {
                    piped: Some(input_actor.clone()),
                    ..actor_context.clone()
                },
                reference_connector: std::sync::Weak::new(),
                link_connector: std::sync::Weak::new(),
                module_loader: ModuleLoader::default(),
                source_code,
                function_registry_snapshot: None,
                current_module: None,
            },
            false,
            &function_registry,
        )
        .expect("lazy piped round user-defined function should evaluate")
        .expect("lazy piped round user-defined function should produce an actor");

        crate::engine::REGISTRY.with(|reg| {
            let reg = reg.borrow();
            assert_eq!(
                reg.async_source_count_for_scope(scope_id),
                baseline_async_source_count + 2,
                "lazy builtin direct-actor piped user-defined functions should add one scope-owned watcher plus the first-demand lazy input task"
            );
        });

        assert!(
            result_actor.current_value().is_err(),
            "lazy piped round function actor should stay empty until the first input arrives"
        );

        input_tx
            .try_send(crate::engine::Number::new_value(
                crate::engine::ConstructInfo::new(
                    "test.function_round_direct_state_lazy.initial",
                    None,
                    "test function round direct state lazy initial",
                ),
                construct_context.clone(),
                crate::engine::ValueIdempotencyKey::new(),
                1.2,
            ))
            .expect("lazy piped round input should enqueue");
        crate::engine::poll_test_async_source_tasks();

        let Value::Number(number, _) = result_actor
            .current_value()
            .expect("lazy piped round function actor should resolve after first input")
        else {
            panic!("lazy piped round function actor should resolve to a number");
        };
        assert_eq!(number.number(), 1.0);

        input_tx
            .try_send(crate::engine::Number::new_value(
                crate::engine::ConstructInfo::new(
                    "test.function_round_direct_state_lazy.update",
                    None,
                    "test function round direct state lazy update",
                ),
                construct_context,
                crate::engine::ValueIdempotencyKey::new(),
                2.8,
            ))
            .expect("second lazy piped round input should enqueue");
        crate::engine::poll_test_async_source_tasks();

        let Value::Number(number, _) = result_actor
            .current_value()
            .expect("lazy piped round function actor should keep following lazy input updates")
        else {
            panic!("lazy piped round function actor should stay a number after update");
        };
        assert_eq!(number.number(), 3.0);
    }

