    #[test]
    fn variable_persistence_direct_state_actor_with_lazy_source_uses_one_scope_task_and_skips_first_source_after_restore()
     {
        let scope_id = crate::engine::create_registry_scope(None);
        let _scope_guard = ScopeDestroyGuard::new(scope_id);
        let actor_context = ActorContext {
            registry_scope_id: Some(scope_id),
            ..ActorContext::default()
        };
        let persistence_id = boon::parser::PersistenceId::new();
        let scoped_id = persistence_id.in_scope(&actor_context.scope);
        let construct_context = ConstructContext {
            construct_storage: Arc::new(crate::engine::ConstructStorage::in_memory_for_tests(
                std::collections::BTreeMap::from([(
                    scoped_id.to_string(),
                    zoon::serde_json::json!("restored"),
                )]),
            )),
            virtual_fs: VirtualFilesystem::new(),
            bridge_scope_id: None,
            scene_ctx: None,
        };
        let (mut source_tx, source_rx) = mpsc::channel::<Value>(8);
        let source_actor = crate::engine::create_actor_lazy(
            source_rx,
            boon::parser::PersistenceId::new(),
            scope_id,
        );
        let baseline_async_source_count =
            crate::engine::REGISTRY.with(|reg| reg.borrow().async_source_count_for_scope(scope_id));

        let persisted_actor = super::create_variable_persistence_actor(
            source_actor,
            construct_context.construct_storage.clone(),
            persistence_id,
            actor_context.scope.clone(),
            construct_context.clone(),
            actor_context.clone(),
            false,
        );

        crate::engine::REGISTRY.with(|reg| {
            let reg = reg.borrow();
            assert_eq!(
                reg.async_source_count_for_scope(scope_id),
                baseline_async_source_count + 2,
                "lazy direct-state variable persistence should add one scope-owned watcher plus the first-demand lazy source task"
            );
        });

        let Value::Text(text, _) = persisted_actor
            .current_value()
            .expect("persisted actor should expose restored value before lazy source emits")
        else {
            panic!("persisted actor should resolve to text");
        };
        assert_eq!(text.text(), "restored");

        source_tx
            .try_send(crate::engine::Text::new_value(
                crate::engine::ConstructInfo::new(
                    "test.variable.persistence.lazy.skip_first_source",
                    None,
                    "test variable persistence lazy skip first source",
                ),
                construct_context.clone(),
                crate::engine::ValueIdempotencyKey::new(),
                "initial",
            ))
            .expect("first lazy source value should enqueue");
        crate::engine::poll_test_async_source_tasks();

        let Value::Text(text, _) = persisted_actor.current_value().expect(
            "persisted actor should keep restored value while skipping first lazy source emission",
        ) else {
            panic!("persisted actor should stay text after skipped lazy source emission");
        };
        assert_eq!(text.text(), "restored");

        source_tx
            .try_send(crate::engine::Text::new_value(
                crate::engine::ConstructInfo::new(
                    "test.variable.persistence.lazy.accept_second_source",
                    None,
                    "test variable persistence lazy accept second source",
                ),
                construct_context.clone(),
                crate::engine::ValueIdempotencyKey::new(),
                "fresh",
            ))
            .expect("second lazy source value should enqueue");
        crate::engine::poll_test_async_source_tasks();

        let Value::Text(text, _) = persisted_actor
            .current_value()
            .expect("persisted actor should accept the second lazy source emission after restore")
        else {
            panic!("persisted actor should stay text after accepting lazy source emission");
        };
        assert_eq!(text.text(), "fresh");

        let saved = construct_context
            .construct_storage
            .load_state_now::<zoon::serde_json::Value>(scoped_id)
            .expect("accepted lazy source value should be persisted");
        assert_eq!(saved, zoon::serde_json::json!("fresh"));
    }

