    #[test]
    fn then_actor_with_spread_object_user_defined_function_body_uses_direct_state_path_without_wrapper_task()
     {
        let scope_id = crate::engine::create_registry_scope(None);
        let _scope_guard = ScopeDestroyGuard::new(scope_id);
        let actor_context = ActorContext {
            registry_scope_id: Some(scope_id),
            ..ActorContext::default()
        };
        let construct_context = ConstructContext {
            construct_storage: Arc::new(crate::engine::ConstructStorage::new("")),
            virtual_fs: VirtualFilesystem::new(),
            bridge_scope_id: None,
            scene_ctx: None,
        };
        let (_, function_expressions) =
            parse_static_program("FUNCTION rounded(x) { x |> Math/round() }");
        let function_def = function_expressions
            .into_iter()
            .find_map(|expr| match expr.node {
                static_expression::Expression::Function {
                    name,
                    parameters,
                    body,
                } if name.to_string() == "rounded" => Some(super::StaticFunctionDefinition {
                    parameters: parameters
                        .into_iter()
                        .map(|param| param.node.to_string())
                        .collect(),
                    body: *body,
                    module_name: None,
                }),
                _ => None,
            })
            .expect("rounded function should parse");
        let registry_snapshot = Arc::new(HashMap::from([(String::from("rounded"), function_def)]));

        let body_source = SourceCode::new("input rounded echoed Number value".to_owned());
        let spread_span: boon::parser::Span = (0..0).into();
        let rounded_span: boon::parser::Span = (6..13).into();
        let echoed_span: boon::parser::Span = (14..20).into();
        let body = static_expression::Spanned {
            span: span_at(body_source.len()),
            persistence: Some(boon::parser::Persistence {
                id: boon::parser::PersistenceId::new(),
                status: boon::parser::PersistenceStatus::NewOrChanged,
            }),
            node: static_expression::Expression::Object(static_expression::Object {
                variables: vec![
                    static_expression::Spanned {
                        span: spread_span,
                        persistence: None,
                        node: static_expression::Variable {
                            name: body_source.slice(0, 0),
                            is_referenced: false,
                            value_changed: false,
                            value: static_expression::Spanned {
                                span: spread_span,
                                persistence: None,
                                node: static_expression::Expression::Spread {
                                    value: Box::new(static_expression::Spanned {
                                        span: spread_span,
                                        persistence: None,
                                        node: static_expression::Expression::Alias(
                                            static_expression::Alias::WithPassed {
                                                extra_parts: vec![],
                                            },
                                        ),
                                    }),
                                },
                            },
                        },
                    },
                    static_expression::Spanned {
                        span: rounded_span,
                        persistence: Some(boon::parser::Persistence {
                            id: boon::parser::PersistenceId::new(),
                            status: boon::parser::PersistenceStatus::NewOrChanged,
                        }),
                        node: static_expression::Variable {
                            name: body_source.slice(6, 13),
                            is_referenced: true,
                            value_changed: false,
                            value: static_expression::Spanned {
                                span: rounded_span,
                                persistence: None,
                                node: static_expression::Expression::Pipe {
                                    from: Box::new(static_expression::Spanned {
                                        span: (0..5).into(),
                                        persistence: None,
                                        node: static_expression::Expression::Alias(
                                            static_expression::Alias::WithPassed {
                                                extra_parts: vec![body_source.slice(0, 5)],
                                            },
                                        ),
                                    }),
                                    to: Box::new(static_expression::Spanned {
                                        span: rounded_span,
                                        persistence: None,
                                        node: static_expression::Expression::FunctionCall {
                                            path: vec![body_source.slice(6, 13)],
                                            arguments: vec![],
                                        },
                                    }),
                                },
                            },
                        },
                    },
                    static_expression::Spanned {
                        span: echoed_span,
                        persistence: Some(boon::parser::Persistence {
                            id: boon::parser::PersistenceId::new(),
                            status: boon::parser::PersistenceStatus::NewOrChanged,
                        }),
                        node: static_expression::Variable {
                            name: body_source.slice(14, 20),
                            is_referenced: false,
                            value_changed: false,
                            value: static_expression::Spanned {
                                span: rounded_span,
                                persistence: None,
                                node: static_expression::Expression::Alias(
                                    static_expression::Alias::WithoutPassed {
                                        parts: vec![body_source.slice(6, 13)],
                                        referenced_span: Some(rounded_span),
                                    },
                                ),
                            },
                        },
                    },
                ],
            }),
        };

        let input_actor =
            crate::engine::create_actor_forwarding(boon::parser::PersistenceId::new(), scope_id);
        input_actor.store_value_directly(crate::engine::Number::new_value(
            crate::engine::ConstructInfo::new("test.spread_then.input", None, "test spread input"),
            construct_context.clone(),
            crate::engine::ValueIdempotencyKey::new(),
            1.2,
        ));
        let echoed_actor =
            crate::engine::create_actor_forwarding(boon::parser::PersistenceId::new(), scope_id);
        echoed_actor.store_value_directly(crate::engine::Number::new_value(
            crate::engine::ConstructInfo::new(
                "test.spread_then.echoed",
                None,
                "test spread echoed",
            ),
            construct_context.clone(),
            crate::engine::ValueIdempotencyKey::new(),
            99.0,
        ));
        let piped_actor =
            crate::engine::create_actor_forwarding(boon::parser::PersistenceId::new(), scope_id);
        piped_actor.store_value_directly(Object::new_value(
            crate::engine::ConstructInfo::new(
                "test.spread_then.object",
                None,
                "test spread object",
            ),
            construct_context.clone(),
            crate::engine::ValueIdempotencyKey::new(),
            [
                Variable::new_arc(
                    crate::engine::ConstructInfo::new(
                        "test.spread_then.input_var",
                        None,
                        "test spread input var",
                    ),
                    "input",
                    input_actor.clone(),
                    boon::parser::PersistenceId::new(),
                    actor_context.scope.clone(),
                ),
                Variable::new_arc(
                    crate::engine::ConstructInfo::new(
                        "test.spread_then.echoed_var",
                        None,
                        "test spread echoed var",
                    ),
                    "echoed",
                    echoed_actor.clone(),
                    boon::parser::PersistenceId::new(),
                    actor_context.scope.clone(),
                ),
            ],
        ));

        let result_actor = super::build_then_actor(
            body,
            span_at(0),
            None,
            boon::parser::PersistenceId::new(),
            super::EvaluationContext {
                construct_context: construct_context.clone(),
                actor_context: ActorContext {
                    piped: Some(piped_actor.clone()),
                    registry_scope_id: Some(scope_id),
                    ..actor_context.clone()
                },
                reference_connector: std::sync::Weak::new(),
                link_connector: std::sync::Weak::new(),
                module_loader: ModuleLoader::default(),
                source_code: body_source.clone(),
                function_registry_snapshot: None,
                current_module: None,
            },
            registry_snapshot,
        )
        .expect("THEN actor with spread object user-defined direct body should build");

        crate::engine::REGISTRY.with(|reg| {
            let reg = reg.borrow();
            assert_eq!(
                reg.async_source_count_for_scope(scope_id),
                0,
                "THEN with spread object user-defined direct body should stay on runtime subscribers without a wrapper task"
            );
        });

        input_actor.store_value_directly(crate::engine::Number::new_value(
            crate::engine::ConstructInfo::new(
                "test.spread_then.input_update",
                None,
                "test spread input update",
            ),
            construct_context.clone(),
            crate::engine::ValueIdempotencyKey::new(),
            2.8,
        ));
        piped_actor.store_value_directly(Object::new_value(
            crate::engine::ConstructInfo::new(
                "test.spread_then.object_update",
                None,
                "test spread object update",
            ),
            construct_context.clone(),
            crate::engine::ValueIdempotencyKey::new(),
            [
                Variable::new_arc(
                    crate::engine::ConstructInfo::new(
                        "test.spread_then.input_var_update",
                        None,
                        "test spread input var update",
                    ),
                    "input",
                    input_actor.clone(),
                    boon::parser::PersistenceId::new(),
                    actor_context.scope.clone(),
                ),
                Variable::new_arc(
                    crate::engine::ConstructInfo::new(
                        "test.spread_then.echoed_var_update",
                        None,
                        "test spread echoed var update",
                    ),
                    "echoed",
                    echoed_actor.clone(),
                    boon::parser::PersistenceId::new(),
                    actor_context.scope.clone(),
                ),
            ],
        ));

        let Value::Object(object, _) = result_actor
            .current_value()
            .expect("THEN spread object body should expose an object")
        else {
            panic!("THEN spread object body should resolve to an object");
        };
        let Value::Number(input, _) = object
            .expect_variable("input")
            .value_actor()
            .current_value()
            .expect("spread input field should expose a number")
        else {
            panic!("spread input field should resolve to a number");
        };
        let Value::Number(echoed, _) = object
            .expect_variable("echoed")
            .value_actor()
            .current_value()
            .expect("spread echoed field should expose a number")
        else {
            panic!("spread echoed field should resolve to a number");
        };
        let Value::Number(rounded, _) = object
            .expect_variable("rounded")
            .value_actor()
            .current_value()
            .expect("spread rounded field should expose a number")
        else {
            panic!("spread rounded field should resolve to a number");
        };
        assert_eq!(input.number(), 2.8);
        assert_eq!(rounded.number(), 3.0);
        assert_eq!(echoed.number(), 3.0);
    }

